1	export type Cell = [number, number];
2	
3	function countNeighbors(cell: Cell, livingCells: Cell[]): number {
4	  return livingCells.filter(
5	    (other) =>
6	      !(other[0] === cell[0] && other[1] === cell[1]) &&
7	      Math.abs(other[0] - cell[0]) <= 1 &&
8	      Math.abs(other[1] - cell[1]) <= 1
9	  ).length;
10	}
11	
12	export function nextGeneration(livingCells: Cell[]): Cell[] {
13	  return livingCells.filter((cell) => {
14	    const neighborCount = countNeighbors(cell, livingCells);
15	    return neighborCount === 2 || neighborCount === 3;
16	  });
17	}
